        scrollView.addView(contentContainer)
        setContentView(scrollView)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingIntent(intent)
    }

    private fun handleIncomingIntent(intent: Intent?) {
        if (intent == null) {
            showError("No intent received")
            return
        }

        when (intent.action) {
            Intent.ACTION_SEND -> {
                val mimeType = intent.type ?: ""
                when {
                    mimeType == "text/plain" -> handleSharedText(intent)
                    mimeType.startsWith("image/") -> handleSharedImage(intent)
                    else -> showError("Unsupported content type: $mimeType")
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                val mimeType = intent.type ?: ""
                if (mimeType.startsWith("image/")) {
                    handleSharedMultipleImages(intent)
                } else {
                    showError("Unsupported multiple content type: $mimeType")
                }
            }
            else -> {
                showError("Unsupported action: ${intent.action}")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)

        if (sharedText.isNullOrEmpty()) {
            showError("No text content found in shared intent")
            return
        }

        imagePreview.setImageDrawable(null)

        val extractedUrl = extractUrl(sharedText)

        if (extractedUrl != null) {
            statusTextView.text = "Received Shared URL"
            val details = buildString {
                if (!sharedSubject.isNullOrEmpty()) {
                    appendLine("Subject: $sharedSubject")
                    appendLine()
                }
                appendLine("URL: $extractedUrl")
                appendLine()
                appendLine("Full shared text:")
                appendLine(sharedText)
            }
            contentTextView.text = details
            processSharedUrl(extractedUrl)
        } else {
            statusTextView.text = "Received Shared Text"
            val details = buildString {
                if (!sharedSubject.isNullOrEmpty()) {
                    appendLine("Subject: $sharedSubject")
                    appendLine()
                }
                appendLine("Text content:")
                appendLine(sharedText)
            }
            contentTextView.text = details
            processSharedText(sharedText, sharedSubject)
        }

        Log.d(TAG, "Shared text processed: ${sharedText.take(100)}")
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri == null) {
            showError("No image found in shared intent")
            return
        }

        statusTextView.text = "Received Shared Image"
        val details = buildString {
            appendLine("Image URI: $imageUri")
            appendLine("MIME Type: ${intent.type}")
            appendLine()
            appendLine("Image details:")
            appendLine("  Scheme: ${imageUri.scheme}")
            appendLine("  Path: ${imageUri.path}")
        }
        contentTextView.text = details

        try {
            contentResolver.takePersistableUriPermission(
                imageUri,
                Intent.FLAG_GRANT_READ_URI_PERMISSION
            )
        } catch (e: SecurityException) {
            Log.d(TAG, "Could not take persistable URI permission: ${e.message}")
        }

        try {
            imagePreview.setImageURI(imageUri)
        } catch (e: Exception) {
            Log.e(TAG, "Error loading image preview", e)
            imagePreview.setImageDrawable(null)
        }

        processSharedImage(imageUri, intent.type)
        Log.d(TAG, "Shared image processed: $imageUri")
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris.isNullOrEmpty()) {
            showError("No images found in shared intent")
            return
        }

        statusTextView.text = "Received ${imageUris.size} Shared Images"
        val details = buildString {
            appendLine("Number of images: ${imageUris.size}")
            appendLine("MIME Type: ${intent.type}")
            appendLine()
            imageUris.forEachIndexed { index, uri ->
                appendLine("Image ${index + 1}: $uri")
            }
        }
        contentTextView.text = details

        // Show preview of the first image
        try {
            imagePreview.setImageURI(imageUris.first())
        } catch (e: Exception) {
            Log.e(TAG, "Error loading first image preview", e)
            imagePreview.setImageDrawable(null)
        }

        // Add additional image previews to the container
        if (imageUris.size > 1) {
            for (i in 1 until imageUris.size) {
                val additionalImageView = ImageView(this).apply {
                    layoutParams = LinearLayout.LayoutParams(
                        LinearLayout.LayoutParams.MATCH_PARENT,
                        800
                    )
                    adjustViewBounds = true
                    scaleType = ImageView.ScaleType.FIT_CENTER
                    setPadding(0, 8, 0, 8)
                }
                try {
                    additionalImageView.setImageURI(imageUris[i])
                    contentContainer.addView(additionalImageView)
                } catch (e: Exception) {
                    Log.e(TAG, "Error loading image ${i + 1} preview", e)
                }
            }
        }

        processSharedMultipleImages(imageUris, intent.type)
        Log.d(TAG, "Shared ${imageUris.size} images processed")
    }

    private fun extractUrl(text: String): String? {
        val urlPattern = Regex(
            "(https?://[\\w\\-._~:/?#\\[\\]@!$&'()*+,;=%]+)",
            RegexOption.IGNORE_CASE
        )
        val matchResult = urlPattern.find(text)
        val potentialUrl = matchResult?.value

        if (potentialUrl != null) {
            return try {
                URL(potentialUrl)
                potentialUrl
            } catch (e: MalformedURLException) {
                null
            }
        }
        return null
    }

